      type: 'createRailing',
      id: 'seed-rail-stair',
      name: 'Stair railing',
      hostedStairId: 'seed-stair-main',
      pathMm: [
        { xMm: 11400, yMm: 8400 },
        { xMm: 16000, yMm: 8400 },
      ],
    },
    {
      type: 'createRailing',
      id: 'seed-rail-balcony',
      name: 'Balcony railing (horizontal-bar 5×30 mm)',
      pathMm: [
        { xMm: 5000, yMm: 4000 },
        { xMm: 17000, yMm: 4000 },
      ],
    },
    {
      type: 'createRailing',
      id: 'seed-rail-terrace',
      name: 'Terrace edge railing',
      pathMm: [
        { xMm: 5000, yMm: -5000 },
        { xMm: 17000, yMm: -5000 },
      ],
    },
  );

  // ── 13. Rooms (9 — 5 ground + 4 upper) ──────────────────────────────────
  cmds.push(
    {
      type: 'createRoomOutline',
      id: 'seed-room-entrance',
      name: 'Entrance hall',
      levelId: 'seed-lvl-ground',
      programmeCode: 'CIRC',
      outlineMm: [
        { xMm: 5180, yMm: 6180 },
        { xMm: 10900, yMm: 6180 },
        { xMm: 10900, yMm: 8000 },
        { xMm: 5180, yMm: 8000 },
      ],
    },
    {
      type: 'createRoomOutline',
      id: 'seed-room-living',
      name: 'Living',
      levelId: 'seed-lvl-ground',
      programmeCode: 'LIV',
      outlineMm: [
        { xMm: 11100, yMm: 4180 },
        { xMm: 16900, yMm: 4180 },
        { xMm: 16900, yMm: 8000 },
        { xMm: 11100, yMm: 8000 },
      ],
    },
    {
      type: 'createRoomOutline',
      id: 'seed-room-kitchen',
      name: 'Kitchen',
      levelId: 'seed-lvl-ground',
      programmeCode: 'KIT',
      outlineMm: [
        { xMm: 11100, yMm: 8180 },
        { xMm: 16900, yMm: 8180 },
        { xMm: 16900, yMm: 11900 },
