                    level_id="lvl-1",
                    anchor_x_mm=3000,
                    anchor_y_mm=4200,
                    resolved=False,
                    created_at=now,
                    updated_at=now,
                ),
            )

        await session.commit()

    print("seed: OK — demo/main model:", str(MODEL_ID))


def main() -> None:
    asyncio.run(seed_async())


if __name__ == "__main__":
    main()

