178	function makeRoofMassMesh(
179	  roof: Extract<Element, { kind: 'roof' }>,
180	  elementsById: Record<string, Element>,
181	  paint: ViewportPaintBundle | null,
182	): THREE.Mesh {
183	  const b = xzBoundsMm(roof.footprintMm ?? []);
184	
185	  const ov = THREE.MathUtils.clamp((roof.overhangMm ?? 0) / 1000, 0, 5);
186	
187	  const refElev = elevationMForLevel(roof.referenceLevelId, elementsById);
188	  // Eave plate = top of the tallest wall at the reference level.
189	  // Without this, the box proxy sits inside the upper-storey walls and is invisible.
190	  const wallsAtRefLevel = Object.values(elementsById).filter(
191	    (e): e is WallElem => e.kind === 'wall' && (e as WallElem).levelId === roof.referenceLevelId,
192	  );
193	  const wallTopM =
194	    wallsAtRefLevel.length > 0
195	      ? Math.max(...wallsAtRefLevel.map((w) => (w.heightMm ?? 0) / 1000))
196	      : 0;
197	  const elev = refElev + wallTopM;
198	
199	  const rise = THREE.MathUtils.clamp(Number(roof.slopeDeg ?? 25) / 70, 0.25, 2.8);
200	
201	  const spanX = THREE.MathUtils.clamp(b.spanX / 1000 + ov * 0.08, 3, 200);
202	
203	  const spanZ = THREE.MathUtils.clamp(b.spanZ / 1000 + ov * 0.08, 3, 200);
204	
205	  const mesh = new THREE.Mesh(
206	    new THREE.BoxGeometry(spanX, rise, spanZ),
207	
208	    new THREE.MeshStandardMaterial({
209	      color: categoryColorOr(paint, 'roof'),
210	      transparent: true,
211	      opacity: 0.94,
212	      roughness: paint?.categories.roof.roughness ?? 0.74,
213	      metalness: 0.04,
214	    }),
215	  );
216	
217	  mesh.position.set(b.cx / 1000, elev + ov * 0.12 + rise / 2, b.cz / 1000);
218	
219	  mesh.userData.bimPickId = roof.id;
220	
221	  return mesh;
222	}
