224	function makeStairVolumeMesh(
225	  stair: Extract<Element, { kind: 'stair' }>,
226	  elementsById: Record<string, Element>,
227	  paint: ViewportPaintBundle | null,
228	  selectedId?: string,
229	): THREE.Mesh {
230	  const sx = stair.runStartMm.xMm / 1000;
231	
232	  const sz = stair.runStartMm.yMm / 1000;
233	
234	  const ex = stair.runEndMm.xMm / 1000;
235	
236	  const ez = stair.runEndMm.yMm / 1000;
237	
238	  const dx = ex - sx;
239	
240	  const dz = ez - sz;
241	
242	  const len = Math.max(1e-3, Math.hypot(dx, dz));
243	
244	  const width = THREE.MathUtils.clamp(stair.widthMm / 1000, 0.3, 4);
245	
246	  const bl = elementsById[stair.baseLevelId];
247	
248	  const tl = elementsById[stair.topLevelId];
249	
250	  const riseMm =
251	    bl?.kind === 'level' && tl?.kind === 'level'
252	      ? Math.abs(tl.elevationMm - bl.elevationMm)
253	      : stair.riserMm * 16;
254	
255	  const rise = THREE.MathUtils.clamp(riseMm / 1000, 0.5, 12);
256	
257	  const elevBase = elevationMForLevel(stair.baseLevelId, elementsById);
258	
259	  const mesh = new THREE.Mesh(
260	    new THREE.BoxGeometry(len, rise, width),
261	
262	    new THREE.MeshStandardMaterial({
263	      color:
264	        stair.id === selectedId
265	          ? (paint?.selection.selectedColor ?? '#fcd34d')
266	          : categoryColorOr(paint, 'stair'),
267	    }),
268	  );
